Replace the three-tab Radix `Tabs` layout in `CreateAgentDialog.tsx` with a step-based wizard using `AnimatePresence` transitions. This is the core rewrite — method cards on step 1, template picker on step 2a, configure form on step 2b, import on step 2c.

## File to modify

### `apps/client/src/layers/features/agent-creation/ui/CreateAgentDialog.tsx`

Complete rewrite of the component. Remove all `Tabs`, `TabsList`, `TabsTrigger`, `TabsContent` imports and usage. Add `AnimatePresence`, `motion` from `motion/react`.

#### Types (add at top of file)

```typescript
type CreationMode = 'new' | 'template' | 'import';
type WizardStep = 'choose' | 'pick-template' | 'configure' | 'import';
```

#### New imports

```typescript
import { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { ChevronDown, FolderOpen, FileText, Package, Search, ArrowLeft } from 'lucide-react';
import { AnimatePresence, motion } from 'motion/react';
import { toast } from 'sonner';
import { validateAgentName } from '@dorkos/shared/validation';
import { useQuery } from '@tanstack/react-query';
import { useTransport, type CreationMode as CreationModeType } from '@/layers/shared/model';
import { playCelebration } from '@/layers/shared/lib';
import { cn } from '@/layers/shared/lib';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  Button,
  Input,
  Label,
  Collapsible,
  CollapsibleTrigger,
  CollapsibleContent,
} from '@/layers/shared/ui';
import { DiscoveryView } from '@/layers/features/mesh';
import { useAgentCreationStore } from '../model/store';
import { useCreateAgent } from '../model/use-create-agent';
import { TemplatePicker } from './TemplatePicker';
```

#### Step state machine

Replace the tab state with wizard step state:

```typescript
// Derive initial step from store's initialMode
function initialStepFromMode(mode: CreationModeType): WizardStep {
  switch (mode) {
    case 'template': return 'pick-template';
    case 'import': return 'import';
    default: return 'choose';
  }
}
```

Inside the component:

```typescript
const { isOpen, initialMode, close } = useAgentCreationStore();

// Wizard state
const [step, setStep] = useState<WizardStep>('choose');
const [creationMode, setCreationMode] = useState<CreationMode>('new');
const [template, setTemplate] = useState<string | null>(null);
const [templateName, setTemplateName] = useState<string | null>(null);

// Sync step from store when dialog opens
const [prevIsOpen, setPrevIsOpen] = useState(false);
if (isOpen !== prevIsOpen) {
  setPrevIsOpen(isOpen);
  if (isOpen) {
    const startStep = initialStepFromMode(initialMode);
    setStep(startStep);
    setCreationMode(initialMode === 'import' ? 'import' : initialMode === 'template' ? 'template' : 'new');
  }
}
```

#### Method Selection component (inline or extracted)

```typescript
function MethodSelection({ onSelect }: { onSelect: (mode: CreationMode) => void }) {
  const methods = [
    {
      mode: 'new' as CreationMode,
      icon: <FileText className="size-5" />,
      iconBg: 'bg-indigo-500/10 text-indigo-600 dark:text-indigo-400',
      title: 'Start Blank',
